23	// harnessRateLimitCache holds the most recently observed rate-limit signal per
24	// harness name. The server invocation path (or tests) populates it via
25	// RecordHarnessRateLimit; quotaFromHarnessInfo reads it when the upstream
26	// HarnessInfo.Quota does not carry token-level ceilings.
27	var harnessRateLimitCache = struct {
28		sync.RWMutex
29		byName map[string]agent.RateLimitSignal
30	}{byName: make(map[string]agent.RateLimitSignal)}
31	
32	// RecordHarnessRateLimit stores the latest parsed rate-limit signal for a
33	// harness invocation. Intended for the server's harness-dispatch path to call
34	// after each response; tests use it directly.
35	func RecordHarnessRateLimit(name string, sig agent.RateLimitSignal) {
36		name = strings.TrimSpace(name)
37		if name == "" || !sig.HasAny() {
38			return
39		}
40		harnessRateLimitCache.Lock()
41		harnessRateLimitCache.byName[name] = sig
42		harnessRateLimitCache.Unlock()
43	}
44	
45	// LookupHarnessRateLimit returns the last-observed signal for a harness, or
46	// ok=false if none has been recorded.
47	func LookupHarnessRateLimit(name string) (agent.RateLimitSignal, bool) {
48		harnessRateLimitCache.RLock()
49		defer harnessRateLimitCache.RUnlock()
50		sig, ok := harnessRateLimitCache.byName[name]
51		return sig, ok
52	}
53	
54	// resetHarnessRateLimitCache is a test seam.
55	func resetHarnessRateLimitCache() {
56		harnessRateLimitCache.Lock()
57		harnessRateLimitCache.byName = make(map[string]agent.RateLimitSignal)
58		harnessRateLimitCache.Unlock()
59	}
