61	// ProviderStatuses is the resolver for the providerStatuses field.
62	// It mirrors the output of `ddx agent providers`, annotating each row with
63	// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
64	// the sessions index. Quota is populated when the upstream ProviderInfo
65	// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
66	func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
67		now := time.Now().UTC()
68		entries := r.sessionIndexEntries()
69	
70		if rows := cachedProviderRows(r.WorkingDir); len(rows) > 0 {
71			refreshProviderStatuses(r.WorkingDir)
72			return providerRowsWithUsage(rows, entries, now), nil
73		}
74	
75		if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.WorkingDir); err == nil && ok {
76			rows := providerStatusesFromInfos(snapshots, entries, now)
77			storeProviderRows(r.WorkingDir, rows)
78			refreshProviderStatuses(r.WorkingDir)
79			return rows, nil
80		} else if err != nil {
81			return nil, fmt.Errorf("loading provider snapshots: %w", err)
82		}
83	
84		// Legacy/global provider config fallback. Bound the synchronous path so the
85		// UI can still first-paint harness rows even if provider probing is slow.
86		probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
87		defer cancel()
88		providers, err := liveProviderInfos(probeCtx, r.WorkingDir)
89		if err != nil {
90			refreshProviderStatuses(r.WorkingDir)
91			return []*ProviderStatus{}, nil
92		}
93		rows := providerStatusesFromInfos(providers, entries, now)
94		storeProviderRows(r.WorkingDir, rows)
95		return rows, nil
96	}
