98	// HarnessStatuses is the resolver for the harnessStatuses field.
99	// It returns one row per subprocess harness (kind=HARNESS). Reachability is
100	// taken from HarnessInfo.Available, rolling usage from the sessions index,
101	// and quota from the harness-reported rate-limit data when available.
102	func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
103		svc, err := agentlib.New(agentlib.ServiceOptions{})
104		if err != nil {
105			return []*ProviderStatus{}, nil //nolint:nilerr
106		}
107		infos, err := svc.ListHarnesses(ctx)
108		if err != nil {
109			return nil, fmt.Errorf("listing harnesses: %w", err)
110		}
111	
112		now := time.Now().UTC()
113		entries := r.sessionIndexEntries()
114		lastChecked := now.Format(time.RFC3339)
115	
116		results := make([]*ProviderStatus, 0, len(infos))
117		for _, info := range infos {
118			ps := &ProviderStatus{
119				Name:              info.Name,
120				Kind:              ProviderKindHarness,
121				ProviderType:      harnessTypeLabel(info),
122				BaseURL:           "(subprocess)",
123				Model:             info.DefaultModel,
124				Status:            harnessStatusLine(info),
125				Reachable:         info.Available,
126				Detail:            harnessDetail(info),
127				ModelCount:        harnessModelCount(info),
128				IsDefault:         false,
129				LastCheckedAt:     strPtr(lastChecked),
130				DefaultForProfile: []string{},
131			}
132			ps.Usage = buildUsage(entries, info.Name, agent.MatchHarness, now)
133			ps.Quota = quotaFromHarnessInfo(info)
134			ps.Sparkline = buildSparkline(entries, info.Name, agent.MatchHarness, now)
135			results = append(results, ps)
136		}
137	
138		return results, nil
139	}
