142	func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
143		svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
144		if err != nil {
145			return nil, nil //nolint:nilerr
146		}
147		dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
148		if err != nil {
149			return &DefaultRouteStatus{}, nil //nolint:nilerr
150		}
151		result := &DefaultRouteStatus{ModelRef: dec.Model}
152		if dec.Provider != "" {
153			p := dec.Provider
154			result.ResolvedProvider = &p
155		}
156		if dec.Model != "" {
157			m := dec.Model
158			result.ResolvedModel = &m
159		}
160		return result, nil
