163	// ProviderTrend is the resolver for the providerTrend field.
164	// It aggregates the sessions index into time buckets for one provider/harness
165	// and computes a projected-run-out-in-hours callout from the last-24h slope.
166	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
167		name = strings.TrimSpace(name)
168		if name == "" {
169			return nil, fmt.Errorf("name required")
170		}
171		if windowDays != 7 && windowDays != 30 {
172			return nil, fmt.Errorf("windowDays must be 7 or 30")
173		}
174		now := time.Now().UTC()
175		entries := r.sessionIndexEntries()
176	
177		kind, detected := detectProviderOrHarness(ctx, r, name)
178		bucketKind := agent.MatchProvider
179		if kind == ProviderKindHarness {
180			bucketKind = agent.MatchHarness
181		}
182	
183		bucketSize := time.Hour
184		if windowDays > 7 {
185			bucketSize = 4 * time.Hour
186		}
187		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
188		series := make([]*ProviderTrendPoint, 0, len(buckets))
189		for _, b := range buckets {
190			series = append(series, &ProviderTrendPoint{
191				BucketStart: b.Start.UTC().Format(time.RFC3339),
192				Tokens:      b.Tokens,
193				Requests:    b.Requests,
194			})
195		}
196	
197		trend := &ProviderTrend{
198			Name:       name,
199			Kind:       kind,
200			WindowDays: windowDays,
201			Series:     series,
202		}
203	
204		if detected != nil {
205			if ceiling := detected.ceilingTokens; ceiling > 0 {
206				c := ceiling
207				trend.CeilingTokens = &c
208				remaining := detected.remaining
209				if remaining < 0 {
210					remaining = ceiling - sumTailTokens(buckets, 24)
211				}
212				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
213					trend.ProjectedRunOutHours = &p
214				}
215			}
216		}
217	
218		return trend, nil
219	}
