221	// --------- helpers ---------
222	
223	type detectedRow struct {
224		ceilingTokens int
225		remaining     int
226	}
227	
228	// detectProviderOrHarness looks up a name against providers first, then
229	// harnesses, returning the resolved kind and quota signal (if any).
230	func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
231		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
232			harnesses, _ := svc.ListHarnesses(ctx)
233			for _, h := range harnesses {
234				if strings.EqualFold(h.Name, name) {
235					q := quotaFromHarnessInfo(h)
236					return ProviderKindHarness, detectedFromQuota(q)
237				}
238			}
239		}
240		if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.WorkingDir); ok {
241			for _, p := range snapshots {
242				if strings.EqualFold(p.Name, name) {
243					q := quotaFromProviderInfo(p)
244					return ProviderKindEndpoint, detectedFromQuota(q)
245				}
246			}
247		}
248		if providers, err := liveProviderInfos(ctx, r.WorkingDir); err == nil {
249			for _, p := range providers {
250				if strings.EqualFold(p.Name, name) {
251					q := quotaFromProviderInfo(p)
252					return ProviderKindEndpoint, detectedFromQuota(q)
253				}
254			}
255		}
256		return ProviderKindEndpoint, nil
257	}
258	
259	func detectedFromQuota(q *ProviderQuota) *detectedRow {
260		if q == nil {
261			return nil
262		}
263		row := &detectedRow{ceilingTokens: -1, remaining: -1}
264		if q.CeilingTokens != nil {
265			row.ceilingTokens = *q.CeilingTokens
266		}
267		if q.Remaining != nil {
268			row.remaining = *q.Remaining
269		}
270		return row
271	}
