329	func liveProviderInfos(ctx context.Context, workDir string) ([]agentlib.ProviderInfo, error) {
330		svc, err := agent.NewStatusProbeServiceFromWorkDir(workDir)
331		if err != nil {
332			return nil, err
333		}
334		return svc.ListProviders(ctx)
335	}
