337	func refreshProviderStatuses(workDir string) {
338		providerStatusCache.Lock()
339		if providerStatusCache.inFlight[workDir] {
340			providerStatusCache.Unlock()
341			return
342		}
343		providerStatusCache.inFlight[workDir] = true
344		providerStatusCache.Unlock()
345	
346		go func() {
347			defer func() {
348				providerStatusCache.Lock()
349				delete(providerStatusCache.inFlight, workDir)
350				providerStatusCache.Unlock()
351			}()
352			ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
353			defer cancel()
354			providers, err := liveProviderInfos(ctx, workDir)
355			if err != nil {
356				return
357			}
358			rows := providerStatusesFromInfos(providers, nil, time.Now().UTC())
359			storeProviderRows(workDir, rows)
360		}()
361	}
362	
363	func cachedProviderRows(workDir string) []*ProviderStatus {
364		providerStatusCache.Lock()
365		defer providerStatusCache.Unlock()
366		return cloneProviderRows(providerStatusCache.rows[workDir])
367	}
368	
369	func storeProviderRows(workDir string, rows []*ProviderStatus) {
370		providerStatusCache.Lock()
371		defer providerStatusCache.Unlock()
372		providerStatusCache.rows[workDir] = cloneProviderRows(rows)
373	}
