375	func providerStatusesFromInfos(providers []agentlib.ProviderInfo, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
376		lastChecked := now.UTC().Format(time.RFC3339)
377		results := make([]*ProviderStatus, 0, len(providers))
378		for _, p := range providers {
379			url := p.BaseURL
380			if url == "" {
381				url = "(api)"
382			}
383			ps := &ProviderStatus{
384				Name:              p.Name,
385				Kind:              ProviderKindEndpoint,
386				ProviderType:      p.Type,
387				BaseURL:           url,
388				Model:             p.DefaultModel,
389				Status:            p.Status,
390				Reachable:         providerReachable(p),
391				Detail:            providerDetail(p),
392				ModelCount:        p.ModelCount,
393				IsDefault:         p.IsDefault,
394				LastCheckedAt:     strPtr(lastChecked),
395				DefaultForProfile: defaultProfilesForEndpoint(p),
396			}
397			if ps.ProviderType == "" {
398				ps.ProviderType = "endpoint"
399			}
400			if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
401				s := p.CooldownState.Until.UTC().Format(time.RFC3339)
402				ps.CooldownUntil = &s
403			}
404			ps.Usage = buildUsage(entries, p.Name, agent.MatchProvider, now)
405			ps.Quota = quotaFromProviderInfo(p)
406			ps.Sparkline = buildSparkline(entries, p.Name, agent.MatchProvider, now)
407			results = append(results, ps)
408		}
409		return results
410	}
