412	func providerRowsWithUsage(rows []*ProviderStatus, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
413		out := cloneProviderRows(rows)
414		for _, row := range out {
415			row.Usage = buildUsage(entries, row.Name, agent.MatchProvider, now)
416			row.Sparkline = buildSparkline(entries, row.Name, agent.MatchProvider, now)
417		}
418		return out
419	}
