466	// sessionIndexEntries reads the project's session index for all available
467	// shards. Errors are swallowed — a missing index is a normal "no data" state.
468	func (r *queryResolver) sessionIndexEntries() []agent.SessionIndexEntry {
469		logDir := agent.SessionLogDirForWorkDir(r.WorkingDir)
470		if logDir == "" {
471			return nil
472		}
473		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
474		if err != nil {
475			return nil
476		}
477		return entries
