480	func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
481		counts := agent.AggregateUsageCounts(entries, name, kind, now)
482		// FEAT-014 no-fabrication: when the session index has no rows attributable
483		// to this name, return nil so the UI renders "not reported" instead of
484		// fabricated "0 / 0" counts.
485		if counts.TokensLastHour == 0 && counts.TokensLast24h == 0 &&
486			counts.RequestsLastHour == 0 && counts.RequestsLast24h == 0 {
487			return nil
488		}
489		u := &ProviderUsage{}
490		v := counts.TokensLastHour
491		u.TokensUsedLastHour = &v
492		v2 := counts.TokensLast24h
493		u.TokensUsedLast24h = &v2
494		v3 := counts.RequestsLastHour
495		u.RequestsLastHour = &v3
496		v4 := counts.RequestsLast24h
497		u.RequestsLast24h = &v4
498		return u
499	}
