501	// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
502	// Returns nil when no token-level ceiling is published.
503	func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
504		if p.Quota == nil {
505			return nil
506		}
507		return quotaFromState(p.Quota)
508	}
509	
510	// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
511	// When a rate-limit signal has been captured for this harness (via
512	// RecordHarnessRateLimit — typically on the server's harness-dispatch path
513	// after parsing response headers with agent.ParseRateLimitHeaders), that
514	// signal takes precedence because it carries absolute token ceilings. The
515	// upstream HarnessInfo.Quota only exposes percent-used windows without an
516	// absolute ceiling. Returns nil when nothing usable is published.
517	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
518		if sig, ok := LookupHarnessRateLimit(info.Name); ok {
519			if q := QuotaFromRateLimitSignal(sig); q != nil {
520				return q
521			}
522		}
523		if info.Quota == nil {
524			return nil
525		}
526		return quotaFromState(info.Quota)
527	}
528	
529	// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
530	// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
531	// used), so we surface the window length and reset time only. Ceiling and
532	// remaining stay unknown unless a harness-specific rate-limit-header path
533	// populates them via QuotaFromRateLimitSignal.
534	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
535		if state == nil || len(state.Windows) == 0 {
536			return nil
537		}
538		var windowSeconds int
539		var resetAt string
540		for _, w := range state.Windows {
541			if strings.EqualFold(w.LimitID, "extra") {
542				continue
543			}
544			if windowSeconds == 0 && w.WindowMinutes > 0 {
545				windowSeconds = w.WindowMinutes * 60
546			}
547			if resetAt == "" {
548				if w.ResetsAt != "" {
549					resetAt = w.ResetsAt
550				} else if w.ResetsAtUnix > 0 {
551					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
552				}
553			}
554			if windowSeconds > 0 && resetAt != "" {
555				break
556			}
557		}
558		if windowSeconds == 0 && resetAt == "" {
559			return nil
560		}
561		q := &ProviderQuota{}
562		if windowSeconds > 0 {
563			v := windowSeconds
564			q.CeilingWindowSeconds = &v
565		}
566		if resetAt != "" {
567			v := resetAt
568			q.ResetAt = &v
569		}
570		return q
571	}
572	
573	// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
574	// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
575	// sites where the server captures harness response headers.
576	func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
577		if !sig.HasAny() {
578			return nil
579		}
580		q := &ProviderQuota{}
581		if sig.CeilingTokens >= 0 {
582			v := sig.CeilingTokens
583			q.CeilingTokens = &v
584		}
585		if sig.CeilingWindowSeconds >= 0 {
586			v := sig.CeilingWindowSeconds
587			q.CeilingWindowSeconds = &v
588		}
589		if sig.Remaining >= 0 {
590			v := sig.Remaining
591			q.Remaining = &v
592		}
593		if !sig.ResetAt.IsZero() {
594			v := sig.ResetAt.UTC().Format(time.RFC3339)
595			q.ResetAt = &v
596		}
597		return q
598	}
599	
600	// defaultProfilesForEndpoint returns the profile names where this endpoint is
601	// a default candidate. Current service surface exposes only a single
602	// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
603	// shape supports multi-profile expansion without breaking callers.
604	func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
605		if p.IsDefault {
606			return []string{"default"}
607		}
608		return []string{}
609	}
610	
611	func providerReachable(p agentlib.ProviderInfo) bool {
612		return strings.EqualFold(strings.TrimSpace(p.Status), "connected")
613	}
614	
615	func providerDetail(p agentlib.ProviderInfo) string {
616		if p.LastError != nil && strings.TrimSpace(p.LastError.Detail) != "" {
617			return p.LastError.Detail
618		}
619		for _, ep := range p.EndpointStatus {
620			if ep.LastError != nil && strings.TrimSpace(ep.LastError.Detail) != "" {
621				return ep.LastError.Detail
622			}
623			if strings.TrimSpace(ep.Status) != "" && !strings.EqualFold(ep.Status, p.Status) {
624				return ep.Status
625			}
626		}
627		if strings.TrimSpace(p.Status) != "" {
628			if strings.EqualFold(p.Status, "unknown") {
629				return "not checked yet"
630			}
631			return p.Status
632		}
