128	// handleAgentCatalog serves GET /api/agent/catalog.
129	// Returns the effective model catalog (file or built-in defaults).
130	func (s *Server) handleAgentCatalog(w http.ResponseWriter, r *http.Request) {
131		path := agent.DefaultModelCatalogPath()
132		cat, err := agent.LoadModelCatalogYAML(path)
133		if err != nil {
134			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
135			return
136		}
137	
138		source := "built-in"
139		var pathOut string
140		var updatedAt string
141	
142		if cat == nil {
143			cat = agent.DefaultModelCatalogYAML()
144		} else {
145			source = "file"
146			pathOut = path
147		}
148	
149		if !cat.UpdatedAt.IsZero() {
150			updatedAt = cat.UpdatedAt.UTC().Format(time.RFC3339)
151		}
152	
153		tiers := make(map[string]AgentCatalogTier, len(cat.Tiers))
154		for tierName, tierDef := range cat.Tiers {
155			surfaces := make(map[string]string, len(tierDef.Surfaces))
156			for k, v := range tierDef.Surfaces {
157				surfaces[k] = v
158			}
159			tiers[tierName] = AgentCatalogTier{
160				Description: tierDef.Description,
161				Surfaces:    surfaces,
162			}
163		}
164	
165		models := cat.Models
166		if models == nil {
167			models = []agent.ModelEntryYAML{}
168		}
169	
170		writeJSON(w, http.StatusOK, AgentCatalogResponse{
171			Source:    source,
172			Path:      pathOut,
173			UpdatedAt: updatedAt,
174			Tiers:     tiers,
175			Models:    models,
176		})
177	}
