179	// handleAgentCapabilities serves GET /api/agent/capabilities.
180	// Query param: harness (optional; defaults to configured default harness).
181	func (s *Server) handleAgentCapabilities(w http.ResponseWriter, r *http.Request) {
182		workDir := s.workingDirForRequest(r)
183		harness := r.URL.Query().Get("harness")
184	
185		ctx, cancel := context.WithTimeout(r.Context(), 10*time.Second)
186		defer cancel()
187	
188		if harness == "" {
189			// Derive default harness from config.
190			svc, err := agent.NewServiceFromWorkDir(workDir)
191			if err != nil {
192				writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
193				return
194			}
195			infos, err := svc.ListHarnesses(ctx)
196			if err != nil {
197				writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
198				return
199			}
200			for _, h := range infos {
201				if h.Available {
202					harness = h.Name
203					break
204				}
205			}
206		}
207	
208		if harness == "" {
209			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "harness required: no harness specified and no available harness found"})
210			return
211		}
212	
213		caps, err := agent.CapabilitiesViaService(ctx, workDir, harness)
214		if err != nil {
215			writeJSON(w, http.StatusNotFound, map[string]string{"error": err.Error()})
216			return
217		}
218		writeJSON(w, http.StatusOK, caps)
219	}
